<?php//------------------------------------ //pre: - //post: print een formulier om de inhoud van de datum aan te passen // verbinding maken connect2db(); // lege records afvangen if (($body=="")|($body=="no entry")){ $query = "delete from bbhc_calendar where date = \"$date\""; mysql_query($query) or die ("Delete failed: $query"); } //kijken of het update of insert is $query = "select * from bbhc_calendar where date=\"$date\""; $result = mysql_query($query) or die ("Update failed"); if (mysql_num_rows($result)==0){ $query = "insert into bbhc_calendar (body,date) values (\"$body\",\"$date\")"; mysql_query($query) or die ("Insert failed: $query"); } else { $query = "update bbhc_calendar set body= \"$body\" where date =\"$date\""; mysql_query($query) or die ("Update failed: $query"); } } function get_body($date){ /*------------------------------------ pre: - post: geeft een array terug met een resultset van alle data */ // maak verbinding: connect2db(); $query = "select body from bbhc_calendar where date=\"$date\""; $result = mysql_query($query) or die ("Query failed"); $body = mysql_fetch_array($result); if ($body[0]==null) return "no entry"; else return $body[0]; } ?>